function toAbortError(reason, message = 'Aborted') {
  if (reason && reason.name === 'AbortError') return reason;
  const err = new Error(reason && reason.message ? reason.message : message);
  try { err.name = 'AbortError'; } catch { try { Object.defineProperty(err, 'name', { value: 'AbortError' }); } catch {} }
  return err;
}

export default async function fetchJson(url, options = {}) {
  const { timeoutMs, signal, fetchFn, ...init } = options;
  const fetcher = fetchFn || (typeof fetch === 'function' ? fetch : null);
  if (!fetcher) throw new Error('fetchFn is required');

  const controller = new AbortController();
  let timeoutId;

  const onAbort = () => {
    controller.abort(toAbortError(signal && signal.reason));
  };

  if (signal) {
    if (signal.aborted) {
      controller.abort(toAbortError(signal.reason));
    } else {
      signal.addEventListener('abort', onAbort, { once: true });
    }
  }

  if (typeof timeoutMs === 'number' && timeoutMs >= 0) {
    timeoutId = setTimeout(() => {
      controller.abort(toAbortError(null, 'Timeout'));
    }, timeoutMs);
  }

  try {
    if (controller.signal.aborted) {
      throw toAbortError(controller.signal.reason);
    }

    const res = await fetcher(url, { ...init, signal: controller.signal });
    if (!res || !res.ok) {
      const status = res && typeof res.status === 'number' ? res.status : 0;
      throw new Error(`HTTP ${status}`);
    }
    return await res.json();
  } finally {
    if (timeoutId) clearTimeout(timeoutId);
    if (signal) signal.removeEventListener('abort', onAbort);
  }
}
